#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int N, M;
    scanf("%d", &N);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    scanf("%d", &M);
    for (int i = 0; i < M; i++) {
        int Li, Ri;
        scanf("%d %d", &Li, &Ri);
        Li--;
        Ri--;
        int max_sum = 0;
        for (int j = Li; j <= Ri; j++) {
            max_sum += A[j];
        }
        int *sums = (int*)malloc((1 << (Ri - Li + 1)) * sizeof(int));
        int count = 0;
        for (int mask = 0; mask < (1 << (Ri - Li + 1)); mask++) {
            int sum = 0;
            for (int j = Li; j <= Ri; j++) {
                if ((mask & (1 << (j - Li))) != 0) {
                    sum += A[j];
                }
            }
            sums[count++] = sum;
        }
        qsort(sums, count, sizeof(int), compare);
        int result = 0;
        while (result <= max_sum && binary_search(sums, count, result) != -1) {
            result++;
        }
        printf("%d\n", result);
        free(sums);
    }
    return 0;
}

int binary_search(int *arr, int n, int target) {
    int left = 0;
    int right = n - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (arr[mid] == target) {
            return mid;
        } else if (arr[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return -1;
}

