        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = scanner.nextInt();
        }
        int M = scanner.nextInt();
        for (int i = 0; i < M; i++) {
            int Li = scanner.nextInt() - 1;
            int Ri = scanner.nextInt() - 1;
            int max_sum = 0;
            for (int j = Li; j <= Ri; j++) {
                max_sum += A[j];
            }
            int[] sums = new int[1 << (Ri - Li + 1)];
            int count = 0;
            for (int mask = 0; mask < (1 << (Ri - Li + 1)); mask++) {
                int sum = 0;
                for (int j = Li; j <= Ri; j++) {
                    if ((mask & (1 << (j - Li))) != 0) {
                        sum += A[j];
                    }
                }
                sums[count++] = sum;
            }
            Arrays.sort(sums);
            int result = 0;
            while (result <= max_sum && binarySearch(sums, result) != -1) {
                result++;
            }
            System.out.println(result);
        }
    }

    public static int binarySearch(int[] arr, int target) {
        int left = 0;
        int right = arr.length - 1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (arr[mid] == target) {
                return mid;
            } else if (arr[mid] < target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return -1;
    }
}

